mapper.select:
SELECT ID AS id, CUSTOMER_CODE AS customerCode, CUSTOMER_NAME AS customerName, CUSTOMER_SHORT_NAME AS customerShortName, CUSTOMER_TYPE AS customerType, COUNTRY AS country, CURRENCY AS currency, TAX_CATEGORY AS taxCategory, RELATION_TYPE AS relationType, PARENT_CUSTOMER AS parentCustomer, GROUP_NAME AS groupName, CREATOR AS creator, CREATE_TIME AS createTime, APPLY_ORG AS applyOrg, ENABLE_STATUS AS enableStatus, DISABLE_TIME AS disableTime, COMPANY_ID AS companyId, CREATE_USER_NO AS createUserNo, CREATE_DATE_TIME AS createDateTime, UPDATE_USER_NO AS updateUserNo, UPDATE_DATE_TIME AS updateDateTime, REVISION AS revision, IS_DELETE AS isDelete FROM SALE_CUSTOMER_ARCHIVE
IS_DELETE = 0
AND CUSTOMER_CATEGORY = #{param.customerCategory}
AND CUSTOMER_NAME LIKE CONCAT(CONCAT('%', #{param.customerName}), '%')
AND CUSTOMER_CODE = #{param.customerCode}
AND ENABLE_STATUS = #{param.enableStatus}
AND CREATE_TIME >= TO_DATE(#{param.createDateStart}, 'YYYY-MM-DD')
AND CREATE_TIME < TO_DATE(#{param.createDateEnd}, 'YYYY-MM-DD') + 1
ORDER BY CREATE_DATE_TIME DESC
